    import sys
    input = sys.stdin.read
    data = input().split()

    t = int(data[0])
    results = []

    for i in range(1, t + 1):
        s = data[i]
        if can_erase_string(s):
            results.append("YES")
        else:
            results.append("NO")

    for result in results:
        print(result)

