def is_composite(x):
    if x <= 1:
        return False
    for i in range(2, int(x**0.5) + 1):
        if x % i == 0:
            return True
    return False

def find_largest_composite_subset(n, array):
    total_sum = sum(array)

    if is_composite(total_sum):
        return n, list(range(1, n + 1))

    for i in range(n):
        subset_sum = total_sum - array[i]
        if is_composite(subset_sum):
            indices = [j + 1 for j in range(n) if j != i]
            return n - 1, indices

    return 0, []

def main():
    import sys
    input = sys.stdin.read
    data = input().split()

    index = 0
    t = int(data[index])
    index += 1
    results = []

    for _ in range(t):
        n = int(data[index])
        index += 1
        array = list(map(int, data[index:index + n]))
        index += n

        size, indices = find_largest_composite_subset(n, array)
        results.append(f"{size}")
        results.append(" ".join(map(str, indices)))

    print("\n".join(results))

