def flower_growth(t, test_cases):
    results = []
    for case in test_cases:
        n, a = case
        height = 1
        consecutive_unwatered_days = 0
        for i in range(n):
            if a[i] == 1:
                if i > 0 and a[i-1] == 1:
                    height += 5
                else:
                    height += 1
                consecutive_unwatered_days = 0
            else:
                consecutive_unwatered_days += 1
                if consecutive_unwatered_days == 2:
                    height = -1
                    break
        results.append(height)
    return results

if __name__ == "__main__":
