def determine_winner(N, A):
    left = 0
    right = N - 1
    current_max = -1
    turn = 0  # 0 for Alice, 1 for Bob

    while left <= right:
        if A[left] > current_max and A[right] > current_max:
            if A[left] < A[right]:
                current_max = A[left]
                left += 1
            else:
                current_max = A[right]
                right -= 1
        elif A[left] > current_max:
            current_max = A[left]
            left += 1
        elif A[right] > current_max:
            current_max = A[right]
            right -= 1
        else:
            break
        turn = 1 - turn

    if turn == 0:
        return "Bob"
    else:
        return "Alice"

if __name__ == "__main__":
    import sys
    input = sys.stdin.read
    data = input().split()
    N = int(data[0])
    A = list(map(int, data[1:]))
    print(determine_winner(N, A))

