        if A[left] > current_max and A[right] > current_max:
            if A[left] < A[right]:
                current_max = A[left]
                left += 1
            else:
                current_max = A[right]
                right -= 1
        elif A[left] > current_max:
            current_max = A[left]
            left += 1
        elif A[right] > current_max:
            current_max = A[right]
            right -= 1
        else:
            break
        turn = 1 - turn

    if turn == 0:
        return "Bob"
