def is_subsequence(s, t):
    it = iter(s)
    return all(c in it for c in t)

def find_lexicographically_smallest_permutation(S, T):
    sorted_S = sorted(S)
    # Check if T is a subsequence of sorted_S
    if not is_subsequence(sorted_S, T):
        return ''.join(sorted_S)

    # If T is a subsequence, we need to rearrange 'a', 'b', 'c' in sorted_S
    # Count occurrences of 'a', 'b', 'c'
    count_a = sorted_S.count('a')
    count_b = sorted_S.count('b')
    count_c = sorted_S.count('c')

    # Remove 'a', 'b', 'c' from sorted_S
    sorted_S = [ch for ch in sorted_S if ch not in 'abc']

    # Try different permutations of 'a', 'b', 'c' to break the subsequence
    if T == 'abc':
        # Place 'a's first, then 'c's, then 'b's
        result = ['a'] * count_a + ['c'] * count_c + ['b'] * count_b + sorted_S
    elif T == 'acb':
        # Place 'a's first, then 'b's, then 'c's
        result = ['a'] * count_a + ['b'] * count_b + ['c'] * count_c + sorted_S
    elif T == 'bac':
        # Place 'b's first, then 'a's, then 'c's
        result = ['b'] * count_b + ['a'] * count_a + ['c'] * count_c + sorted_S
    elif T == 'bca':
        # Place 'b's first, then 'c's, then 'a's
        result = ['b'] * count_b + ['c'] * count_c + ['a'] * count_a + sorted_S
    elif T == 'cab':
        # Place 'c's first, then 'a's, then 'b's
        result = ['c'] * count_c + ['a'] * count_a + ['b'] * count_b + sorted_S
    elif T == 'cba':
        # Place 'c's first, then 'b's, then 'a's
        result = ['c'] * count_c + ['b'] * count_b + ['a'] * count_a + sorted_S

    return ''.join(result)

def main():
    import sys
    input = sys.stdin.read
    data = input().strip().split('\n')

    t = int(data[0])
    index = 1
    results = []

    for _ in range(t):
        S = data[index].strip()
        T = data[index + 1].strip()
        index += 2
        result = find_lexicographically_smallest_permutation(S, T)
        results.append(result)

    for result in results:
        print(result)

