def is_consistent(t, test_cases):
    results = []
    for s in test_cases:
        n = len(s)
        if s.count('E') == n:
            results.append("YES")
        elif s.count('N') == n:
            if n % 2 == 0:
                results.append("YES")
            else:
                results.append("NO")
        else:
            # Check for mixed cases
            # We need to ensure there are no contradictions
            # We can use a union-find approach to manage connected components
            parent = list(range(n))

            def find(x):
                if parent[x] != x:
                    parent[x] = find(parent[x])
                return parent[x]

            def union(x, y):
                rootX = find(x)
                rootY = find(y)
                if rootX != rootY:
                    parent[rootY] = rootX

            # Process the string
            for i in range(n):
                if s[i] == 'E':
                    union(i, (i + 1) % n)

            # Check for contradictions
            consistent = True
            for i in range(n):
                if s[i] == 'N':
                    if find(i) == find((i + 1) % n):
                        consistent = False
                        break

            if consistent:
                results.append("YES")
            else:
                results.append("NO")

    return results

